package com.lightevents.destinations;
import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="destination_spots")
public class DestinationSpot { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String title; private String city; private String country; private String countryCode; @Column(length=1200) private String imageUrl; private int sortOrder; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getTitle(){return title;} public void setTitle(String v){title=v;} public String getCity(){return city;} public void setCity(String v){city=v;} public String getCountry(){return country;} public void setCountry(String v){country=v;} public String getCountryCode(){return countryCode;} public void setCountryCode(String v){countryCode=v;} public String getImageUrl(){return imageUrl;} public void setImageUrl(String v){imageUrl=v;} public int getSortOrder(){return sortOrder;} public void setSortOrder(int v){sortOrder=v;} public Instant getCreatedAt(){return createdAt;} }
